const NAME_TO_ID: Record<string, string> = {"餐饮":"food","衣服":"tshirt","交通":"bus","网费话费":"phone","学习":"book","日用":"jug","住房":"house","医疗":"medkit","发红包":"redpacket","汽车/加油":"fuel","娱乐":"gamepad","请客送礼":"gift","电器数码":"camera","运动":"dumbbell","理发":"scissors","付费会员":"gem","还钱":"coins","工作":"briefcase","购物":"bag","旅行":"suitcase","人情/借钱":"handshake","买菜":"carrot","管理分类":"gear","咖啡":"coffee","工资":"wallet","兼职":"clockyen","零食":"snack","孩子":"baby","宠物":"paw","烟酒":"wine","美妆":"lipstick","水电煤":"drop","其他":"grid"};

export function iconIdForCategory(name?: string | null): string {
  return (name && NAME_TO_ID[name]) || "grid";
}

export function CategoryIcon({ id, name, size = 24 }: { id?: string; name?: string | null; size?: number }) {
  const key = id ?? iconIdForCategory(name);
  const xml = ICON_XML[key] ?? ICON_XML.grid;
  return <SvgXml xml={xml} width={size} height={size} />;
}
